    $session = $null
    try {
        $session = Get-PseSession
        $result = Send-PseCdp -Conn $session.Conn -Method $method -Params $params
        Write-Output ($result | ConvertTo-Json -Depth 12)
        return 0
    } finally {
        Close-PseSession -Session $session
    }
}

